// Аяты Корана и достоверные хадисы (Кутуб ас-Сitta: Бухари, Муслим, Абу Дауд, ат-Тирмizi, an-Nasa'i, Ibn Majah)
export const QURAN_AYAT = [
  { id: "a001", ar: "بِسْمِ ٱللَّهِ ٱلرَّحْمَٰنِ ٱلرَّحِيمِ ۝ ٱلْحَمْدُ لِلَّهِ رَبِّ ٱلْعَٰلَمِينَ ۝ ٱلرَّحْمَٰنِ ٱلرَّحِيمِ ۝ مَٰلِكِ يَوْمِ ٱلدِّينِ ۝ إِيَّاكَ نَعْبُدُ وَإِيَّاكَ نَسْتَعِينُ ۝ ٱهْدِنَا ٱلصِّرَٰطَ ٱلْمُسْتَقِيمَ ۝ صِرَٰطَ ٱلَّذِينَ أَنْعَمْتَ عَلَيْهِمْ غَيْرِ ٱلْمَغْضُوبِ عَلَيْهِمْ وَلَا ٱلضَّآلِّينَ", ru: "Во имя Аллаха, Милостивого, Милосердного! Хвала Аллаху, Господу миров, Милостивому, Милосердному, Властелину Судного дня! Тебе одному мы поклоняемся и Тебя одного молим о помощи. Веди нас прямым путём — путём тех, кого Ты облагодетельствовал, не тех, на кого пал гнев, и не заблудших.", ref: "Аль-Фатиха, 1:1–7" },
  { id: "a002", ar: "ٱللَّهُ لَآ إِلَٰهَ إِلَّا هُوَ ٱلْحَىُّ ٱلْقَيُّومُ ۚ لَا تَأْخُذُهُۥ سِنَةٌ وَلَا نَوْمٌ ۚ لَّهُۥ مَا فِى ٱلسَّمَٰوَٰتِ وَمَا فِى ٱلْأَرْضِ ۗ مَن ذَا ٱلَّذِى يَشْفَعُ عِندَهُۥٓ إِلَّا بِإِذْنِهِۦ ۚ يَعْلَمُ مَا بَيْنَ أَيْدِيهِمْ وَمَا خَلْفَهُمْ ۖ وَلَا يُحِيطُونَ بِشَىْءٍ مِّنْ عِلْمِهِۦٓ إِلَّا بِمَا شَآءَ ۚ وَسِعَ كُرْسِيُّهُ ٱلسَّمَٰوَٰتِ وَٱلْأَرْضَ ۖ وَلَا يَـُٔودُهُۥ حِفْظُهُمَا ۚ وَهُوَ ٱلْعَلِىُّ ٱلْعَظِيمُ", ru: "Аллах — нет божества, кроме Него, Живого, Сущего. Его не берёт ни дремота, ни сон. Ему принадлежит то, что на небесах и на земле. Кто может заступиться перед Ним иначе как с Его дозволения? Он знает то, что перед ними и то, что позади них, и не охватывают они ничего из Его знания, кроме того, что Он пожелает. Его Престол объемлет небеса и землю, и не тяготит Его их сохранение. Он — Всевышний, Великий.", ref: "Аль-Бакара, 2:255" },
  { id: "a003", ar: "لَا يُكَلِّفُ ٱللَّهُ نَفْسًا إِلَّا وُسْعَهَا ۚ لَهَا مَا كَسَبَتْ وَعَلَيْهَا مَا ٱكْتَسَبَتْ ۗ رَبَّنَا لَا تُؤَاخِذْنَآ إِن نَّسِينَآ أَوْ أَخْطَأْنَا ۚ رَبَّنَا وَلَا تَحْمِلْ عَلَيْنَآ إِسْرًا كَمَا حَمَلْتَهُۥ عَلَى ٱلَّذِينَ مِن قَبْلِنَا ۚ رَبَّنَا وَلَا تُحَمِّلْنَا مَا لَا طَاقَةَ لَنَا بِهِۦ ۖ وَٱعْفُ عَنَّا وَٱغْفِرْ لَنَا وَٱرْحَمْنَآ ۚ أَنتَ مَوْلَىٰنَا فَٱنصُرْنَا عَلَى ٱلْقَوْمِ ٱلْكَٰفِرِينَ", ru: "Аллах не возлагает на душу сверх её возможностей. Ей — то, что она приобрела, и на ней — то, что она заслужила. Господь наш, не взыщи с нас, если мы забыли или ошиблись. Господь наш, не возлагай на нас бремя, как Ты возложил его на тех, кто был до нас. Господь наш, не возлагай на нас того, чего нам не по силам. Прости нас, прости нам и помилуй нас. Ты — наш Покровитель, так помоги нам против неверующих людей.", ref: "Аль-Бакара, 2:286" },
  { id: "a004", ar: "فَٱذْكُرُونِىٓ أَذْكُرْكُمْ وَٱشْكُرُوا۟ لِى وَلَا تَكْفُرُونِ", ru: "Поминайте Меня — и Я буду помнить вас. Благодарите Меня и не будьте неблагодарны.", ref: "Аль-Бакара, 2:152" },
  { id: "a005", ar: "رَبَّنَآ ءَاتِنَا فِى ٱلدُّنْيَا حَسَنَةً وَفِى ٱلْءَاخِرَةِ حَسَنَةً وَقِنَا عَذَابَ ٱلنَّارِ", ru: "Господь наш, даруй нам добро в этом мире и добро в Последней жизни и защити нас от мучений в Огне.", ref: "Аль-Бакара, 2:201" },
  { id: "a006", ar: "يَٰٓأَيُّهَا ٱلَّذِينَ ءَامَنُوا۟ ٱسْتَعِينُوا۟ بِٱلصَّبْرِ وَٱلصَّلَوٰةِ ۚ إِنَّ ٱللَّهَ مَعَ ٱلصَّٰبِرِينَ", ru: "О вы, уверовавшие! Обращайтесь за помощью к терпению и намазу. Воистину, Аллах с терпеливыми.", ref: "Аль-Бакара, 2:153" },
  { id: "a007", ar: "وَإِذَا سَأَلَكَ عِبَادِى عَنِّى فَإِنِّى قَرِيبٌ ۖ أُجِيبُ دَعْوَةَ ٱلدَّاعِ إِذَا دَعَانِ ۖ فَلْيَسْتَجِيبُوا۟ لِى وَلْيُؤْمِنُوا۟ بِى لَعَلَّهُمْ يَرْشُدُونَ", ru: "Если Мои рабы спросят тебя обо Мне, то Я близок. Я отвечаю на зов зовущего, когда он взывает ко Мне. Пусть же они откликнутся Мне и уверуют в Меня, быть может, они пойдут верным путём.", ref: "Аль-Бакара, 2:186" },
  { id: "a008", ar: "وَمَا كَانَ ٱللَّهُ لِيُضِيعَ إِيمَٰنَكُمْ ۚ إِنَّ ٱللَّهَ بِٱلنَّاسِ لَرَءُوفٌ رَّحِيمٌ", ru: "Аллах не даст пропасть вашей вере. Воистину, к людям Аллах — Сострадательный, Милосердный.", ref: "Аль-Бакара, 2:143" },
  { id: "a009", ar: "وَمَا تَفْعَلُوا۟ مِنْ خَيْرٍ يَعْلَمْهُ ٱللَّهُ ۗ وَتَزَوَّدُوا۟ فَإِنَّ خَيْرَ ٱلزَّادِ ٱلتَّقْوَىٰ ۚ وَٱتَّقُونِ يَٰٓأُو۟لِى ٱلْأَلْبَٰبِ", ru: "Какое бы добро вы ни делали — Аллах знает его. Запасайтесь, ибо лучший запас — богобоязненность. Бойтесь Меня, о обладающие разумом!", ref: "Аль-Бакара, 2:197" },
  { id: "a010", ar: "رَبَّنَا لَا تُزِغْ قُلُوبَنَا بَعْدَ إِذْ هَدَيْتَنَا وَهَبْ لَنَا مِن لَّدُنكَ رَحْمَةً ۚ إِنَّكَ أَنتَ ٱلْوَهَّابُ", ru: "Господь наш, не уклоняй наши сердца после того, как Ты наставил нас на прямой путь, и даруй нам от Себя милость. Воистину, Ты — Дарующий.", ref: "Аль-Имран, 3:8" },
  { id: "a011", ar: "قُلِ ٱللَّهُمَّ مَٰلِكَ ٱلْمُلْكِ تُؤْتِى ٱلْمُلْكَ مَن تَشَآءُ وَتَنزِعُ ٱلْمُلْكَ مِمَّن تَشَآءُ وَتُعِزُّ مَن تَشَآءُ وَتُذِلُّ مَن تَشَآءُ ۖ بِيَدِكَ ٱلْخَيْرُ ۖ إِنَّكَ عَلَىٰ كُلِّ شَىْءٍ قَدِيرٌ", ru: "Скажи: «О Аллах, Владыка власти! Ты даруешь власть, кому пожелаешь, и отнимаешь власть у кого пожелаешь, возвышаешь, кого пожелаешь, и унижаешь, кого пожелаешь. В Твоей руке благо. Воистину, Ты способен на всякую вещь».", ref: "Аль-Имран, 3:26" },
  { id: "a012", ar: "ٱلَّذِينَ قَالَ لَهُمُ ٱلنَّاسُ إِنَّ ٱلنَّاسَ قَدْ جَمَعُوا۟ لَكُمْ فَٱخْشَوْهُمْ فَزَادَهُمْ إِيمَٰنًا وَقَالُوا۟ حَسْبُنَا ٱللَّهُ وَنِعْمَ ٱلْوَكِيلُ", ru: "Те, кому люди сказали: «Люди собрались против вас, так бойтесь их», — это лишь приумножило их веру, и они сказали: «Достаточно нам Аллаха, и как прекрасен Он Попечитель!»", ref: "Аль-Имран, 3:173" },
  { id: "a013", ar: "وَلَا تَهِنُوا۟ وَلَا تَحْزَنُوا۟ وَأَنتُمُ ٱلْأَعْلَوْنَ إِن كُنتُم مُّؤْمِنِينَ", ru: "Не унывайте и не печальтесь, ибо вы будете выше, если вы уверовали.", ref: "Аль-Имран, 3:139" },
  { id: "a014", ar: "فَبِمَا رَحْمَةٍ مِّنَ ٱللَّهِ لِنتَ لَهُمْ ۖ وَلَوْ كُنتَ فَظًّا غَلِيظَ ٱلْقَلْبِ لَٱنفَضُّوا۟ مِنْ حَوْلِكَ ۖ فَٱعْفُ عَنْهُمْ وَٱسْتَغْفِرْ لَهُمْ وَشَاوِرْهُمْ فِى ٱلْأَمْرِ ۖ فَإِذَا عَزَمْتَ فَتَوَكَّلْ عَلَى ٱللَّهِ ۚ إِنَّ ٱللَّهَ يُحِبُّ ٱلْمُتَوَكِّلِينَ", ru: "По милости Аллаха ты был мягок с ними. Если бы ты был груб и жёсток сердцем, они разошлись бы вокруг тебя. Так прости их, проси для них прощения и советуйся с ними в деле. Когда же решишься — полагайся на Аллаха. Воистину, Аллах любит полагающихся на Него.", ref: "Аль-Имран, 3:159" },
  { id: "a015", ar: "وَمَن يَعْمَلْ سُوٓءًا أَوْ يَظْلِمْ نَفْسَهُۥ ثُمَّ يَسْتَغْفِرِ ٱللَّهَ يَجِدِ ٱللَّهَ غَفُورًا رَّحِيمًا", ru: "Кто совершит дурное или притеснит самого себя, а потом попросит прощения у Аллаха, тот найдёт Аллаха Прощающим, Милосердным.", ref: "Ан-Ниса, 4:110" },
  { id: "a016", ar: "وَتَعَاوَنُوا۟ عَلَى ٱلْبِرِّ وَٱلتَّقْوَىٰ ۖ وَلَا تَعَاوَنُوا۟ عَلَى ٱلْإِثْمِ وَٱلْعُدْوَٰنِ ۚ وَٱتَّقُوا۟ ٱللَّهَ ۖ إِنَّ ٱللَّهَ شَدِيدُ ٱلْعِقَابِ", ru: "Помогайте друг другу в благочестии и богобоязненности, но не помогайте друг другу в грехе и вражде. Бойтесь Аллаха, ибо Аллах суров в наказании.", ref: "Аль-Маида, 5:2" },
  { id: "a017", ar: "وَٱبْتَغِ فِيمَآ ءَاتَىٰكَ ٱللَّهُ ٱلدَّارَ ٱلْءَاخِرَةَ ۖ وَلَا تَنسَ نَصِيبَكَ مِنَ ٱلدُّنْيَا ۖ وَأَحْسِن كَمَآ أَحْسَنَ ٱللَّهُ إِلَيْكَ ۖ وَلَا تَبْغِ ٱلْفَسَادَ فِى ٱلْأَرْضِ ۖ إِنَّ ٱللَّهَ لَا يُحِبُّ ٱلْمُفْسِدِينَ", ru: "Стремись к дому Последней жизни из того, что Аллах даровал тебе, и не забывай свою долю в этом мире. Твори добро, как Аллах был добр к тебе, и не стремись к распрям на земле. Воистину, Аллах не любит распространяющих нечестие.", ref: "Аль-Касас, 28:77" },
  { id: "a018", ar: "وَرَحْمَتِى وَسِعَتْ كُلَّ شَىْءٍ ۚ فَسَأَكْتُبُهَا لِلَّذِينَ يَتَّقُونَ وَيُؤْتُونَ ٱلزَّكَوٰةَ وَٱلَّذِينَ هُم بِـَٔايَٰتِنَا يُؤْمِنُونَ", ru: "Моя милость объемлет всё сущее. Я предназначу её для тех, кто богобоязнен, выплачивает закят и верует в Наши знамения.", ref: "Аль-Араф, 7:156" },
  { id: "a019", ar: "لَا تَحْزَنْ إِنَّ ٱللَّهَ مَعَنَا", ru: "Не печалься, ведь Аллах с нами.", ref: "Ат-Тауба, 9:40" },
  { id: "a020", ar: "إِنَّ ٱللَّهَ لَا يُضِيعُ أَجْرَ ٱلْمُحْسِنِينَ", ru: "Воистину, Аллах не теряет награды творящих добро.", ref: "Ат-Тауба, 9:120" },
  { id: "a021", ar: "لَقَدْ جَآءَكُمْ رَسُولٌ مِّنْ أَنفُسِكُمْ عَزِيزٌ عَلَيْهِ مَا عَنِتُّمْ حَرِيصٌ عَلَيْكُم بِٱلْمُؤْمِنِينَ رَءُوفٌ رَّحِيمٌ", ru: "К вам явился Посланник из вас самих, которому тяжело то, что причиняет вам трудности, он стремится к вашему благу, к верующим — сострадателен и милосерден.", ref: "Ат-Тауба, 9:128" },
  { id: "a022", ar: "أَلَآ إِنَّ أَوْلِيَآءَ ٱللَّهِ لَا خَوْفٌ عَلَيْهِمْ وَلَا هُمْ يَحْزَنُونَ", ru: "Воистину, друзья Аллаха не испытывают страха и не печалятся.", ref: "Юнус, 10:62" },
  { id: "a023", ar: "وَلَا تَيْـَٔاسُوا۟ مِن رَّوْحِ ٱللَّهِ ۖ إِنَّهُۥ لَا يَيْـَٔاسُ مِن رَّوْحِ ٱللَّهِ إِلَّا ٱلْقَوْمُ ٱلْكَٰفِرُونَ", ru: "Не теряйте надежды на милость Аллаха. Только неверующие люди теряют надежду на милость Аллаха.", ref: "Юсуф, 12:87" },
  { id: "a024", ar: "ٱلَّذِينَ ءَامَنُوا۟ وَتَطْمَئِنُّ قُلُوبُهُم بِذِكْرِ ٱللَّهِ ۗ أَلَا بِذِكْرِ ٱللَّهِ تَطْمَئِنُّ ٱلْقُلُوبُ", ru: "Те, которые уверовали и чьи сердца обретают покой поминанием Аллаха. Воистину, сердца обретают покой поминанием Аллаха.", ref: "Ар-Раад, 13:28" },
  { id: "a025", ar: "إِنَّ ٱللَّهَ لَا يُغَيِّرُ مَا بِقَوْمٍ حَتَّىٰ يُغَيِّرُوا۟ مَا بِأَنفُسِهِمْ", ru: "Воистину, Аллах не меняет положения народа, пока они не изменят то, что в них самих.", ref: "Ар-Раад, 13:11" },
  { id: "a026", ar: "وَإِذْ تَأَذَّنَ رَبُّكُمْ لَئِن شَكَرْتُمْ لَأَزِيدَنَّكُمْ ۖ وَلَئِن كَفَرْتُمْ إِنَّ عَذَابِى لَشَدِيدٌ", ru: "Вот возвестил ваш Господь: «Если вы будете благодарны, Я непременно приумножу вам. А если вы будете неблагодарны, то Моё наказание сурово».", ref: "Ибрахим, 14:7" },
  { id: "a027", ar: "وَقُل رَّبِّ ٱغْفِرْ وَٱرْحَمْ وَأَنتَ خَيْرُ ٱلرَّٰحِمِينَ", ru: "Скажи: «Господи, прости и помилуй, ибо Ты — лучший из милующих».", ref: "Аль-Муминун, 23:118" },
  { id: "a028", ar: "وَعِبَادُ ٱلرَّحْمَٰنِ ٱلَّذِينَ يَمْشُونَ عَلَى ٱلْأَرْضِ هَوْنًا وَإِذَا خَاطَبَهُمُ ٱلْجَٰهِلُونَ قَالُوا۟ سَلَٰمًا", ru: "Рабы Милостивого — те, которые смиренно ходят по земле и, когда невежды обращаются к ним, говорят: «Мир!»", ref: "Аль-Фуркан, 25:63" },
  { id: "a029", ar: "ٱللَّهُ نُورُ ٱلسَّمَٰوَٰتِ وَٱلْأَرْضِ ۚ مَثَلُ نُورِهِۦ كَمِشْكَوٰةٍ فِيهَا مِصْبَاحٌ ۖ ٱلْمِصْبَاحُ فِى زُجَاجَةٍ ۖ ٱلزُّجَاجَةُ كَأَنَّهَا كَوْكَبٌ دُرِّىٌّ يُوقَدُ مِن شَجَرَةٍ مُّبَٰرَكَةٍ زَيْتُونَةٍ لَّا شَرْقِيَّةٍ وَلَا غَرْبِيَّةٍ يَكَادُ زَيْتُهَا يُضِىٓءُ وَلَوْ لَمْ تَمْسَسْهُ نَارٌ ۚ نُّورٌ عَلَىٰ نُورٍ ۗ يَهْدِى ٱللَّهُ لِنُورِهِۦ مَن يَشَآءُ ۚ وَيَضْرِبُ ٱللَّهُ ٱلْأَمْثَٰلَ لِلنَّاسِ ۗ وَٱللَّهُ بِكُلِّ شَىْءٍ عَلِيمٌ", ru: "Аллах — Свет небес и земли. Подобие Его Света — как ниша, в которой светильник. Светильник в стеклянной колбе, а колба — словно сверкающая звезда. Зажигается она от благословенного дерева — оливы, не восточной и не западной, масло которой почти светится, даже если его не коснётся огонь — свет на свете. Аллах ведёт к Своему Свету, кого пожелает. Аллах приводит людям притчи, и Аллах ведает о всякой вещи.", ref: "Ан-Нур, 24:35" },
  { id: "a030", ar: "وَٱلَّذِينَ جَٰهَدُوا۟ فِينَا لَنَهْدِيَنَّهُمْ سُبُلَنَا ۚ وَإِنَّ ٱللَّهَ لَمَعَ ٱلْمُحْسِنِينَ", ru: "Тех, кто сражался на Нашем пути, Мы непременно поведём Нашими путями. Воистину, Аллах с творящими добро.", ref: "Аль-Анкабут, 29:69" },
  { id: "a031", ar: "وَٱلَّذِينَ ءَامَنُوا۟ وَعَمِلُوا۟ ٱلصَّٰلِحَٰتِ لَنُكَفِّرَنَّ عَنْهُمْ سَيِّـَٔاتِهِمْ وَلَنَجْزِيَنَّهُمْ أَحْسَنَ ٱلَّذِى كَانُوا۟ يَعْمَلُونَ", ru: "Тем, которые уверовали и совершали праведные деяния, Мы непременно простим их прегрешения и воздадим им за лучшее из того, что они совершали.", ref: "Аль-Анкабут, 29:7" },
  { id: "a032", ar: "فَٱصْبِرْ إِنَّ وَعْدَ ٱللَّهِ حَقٌّ ۖ وَلَا يَسْتَخِفَّنَّكَ ٱلَّذِينَ لَا يُوقِنُونَ", ru: "Будь терпелив, ибо обещание Аллаха истинно, и пусть не облегчают тебя те, которые не убеждены.", ref: "Ар-Рум, 30:60" },
  { id: "a033", ar: "وَمَن يَتَّقِ ٱللَّهَ يَجْعَل لَّهُۥ مَخْرَجًا ۝ وَيَرْزُقْهُ مِنْ حَيْثُ لَا يَحْتَسِبُ ۚ وَمَن يَتَوَكَّلْ عَلَى ٱللَّهِ فَهُوَ حَسْبُهُ ۚ إِنَّ ٱللَّهَ بَٰلِغُ أَمْرِهِۦ ۚ قَدْ جَعَلَ ٱللَّهُ لِكُلِّ شَىْءٍ قَدْرًا", ru: "Кто боится Аллаха, тому Он устроит выход и наделит его уделом оттуда, откуда он не рассчитывает. Кто полагается на Аллаха, тому Его достаточно. Воистину, Аллах доводит до конца Своё дело. Аллах уже установил меру для всякой вещи.", ref: "Ат-Талак, 65:2–3" },
  { id: "a034", ar: "وَمَن يَتَّقِ ٱللَّهَ يَجْعَل لَّهُۥ مِنْ أَمْرِهِۦ يُسْرًا", ru: "Кто боится Аллаха, тому Он облегчает его дела.", ref: "Ат-Талак, 65:4" },
  { id: "a035", ar: "إِنَّمَا ٱلْمُؤْمِنُونَ إِخْوَةٌ فَأَصْلِحُوا۟ بَيْنَ أَخَوَيْكُمْ ۚ وَٱتَّقُوا۟ ٱللَّهَ لَعَلَّكُمْ تُرْحَمُونَ", ru: "Воистину, верующие — братья. Так примиряйте ваших братьев и бойтесь Аллаха, быть может, вы будете помилованы.", ref: "Аль-Худжурат, 49:10" },
  { id: "a036", ar: "قُلْ يَٰعِبَادِىَ ٱلَّذِينَ أَسْرَفُوا۟ عَلَىٰٓ أَنفُسِهِمْ لَا تَقْنَطُوا۟ مِن رَّحْمَةِ ٱللَّهِ ۚ إِنَّ ٱللَّهَ يَغْفِرُ ٱلذُّنُوبَ جَمِيعًا ۚ إِنَّهُۥ هُوَ ٱلْغَفُورُ ٱلرَّحِيمُ", ru: "Скажи: «О Мои рабы, которые преступили границы дозволенного против самих себя! Не отчаивайтесь в милости Аллаха. Воистину, Аллах прощает все грехи. Воистину, Он — Прощающий, Милосердный».", ref: "Аз-Зумар, 39:53" },
  { id: "a037", ar: "فَتَعَٰلَى ٱللَّهُ ٱلْمَلِكُ ٱلْحَقُّ ۗ وَلَا تَعْجَلْ بِٱلْقُرْءَانِ مِن قَبْلِ أَن يُقْضَىٰٓ إِلَيْكَ وَحْيُهُۥ ۖ وَقُل رَّبِّ زِدْنِى عِلْمًا", ru: "Пречист Аллах, Истинный Царь! Не торопись с Кораном, пока к тебе не будет доведено его внушение, и скажи: «Господи мой, приумножь мне знание!»", ref: "Та-Ха, 20:114" },
  { id: "a038", ar: "رَبِّ ٱشْرَحْ لِى صَدْرِى وَيَسِّرْ لِىٓ أَمْرِى", ru: "Господи, расширь мне грудь и облегчи моё дело.", ref: "Та-Ха, 20:25–26" },
  { id: "a039", ar: "وَهُوَ مَعَكُمْ أَيْنَ مَا كُنتُمْ ۚ وَٱللَّهُ بِمَا تَعْمَلُونَ بَصِيرٌ", ru: "Он с вами, где бы вы ни были. Аллах видит то, что вы совершаете.", ref: "Аль-Хадид, 57:4" },
  { id: "a040", ar: "وَهُوَ ٱلْغَفُورُ ٱلرَّحِيمُ", ru: "Он — Прощающий, Милосердный.", ref: "Аш-Шура, 42:5" },
  { id: "a041", ar: "وَلَسَوْفَ يُعْطِيكَ رَبُّكَ فَتَرْضَىٰٓ", ru: "Твой Господь непременно одарит тебя, и ты будешь доволен.", ref: "Ад-Духа, 93:5" },
  { id: "a042", ar: "فَإِنَّ مَعَ ٱلْعُسْرِ يُسْرًا ۝ إِنَّ مَعَ ٱلْعُسْرِ يُسْرًا", ru: "Ведь рядом с тягостью — облегчение. Воистину, рядом с тягостью — облегчение.", ref: "Аш-Шарх, 94:5–6" },
  { id: "a043", ar: "وَٱلْعَصْرِ ۝ إِنَّ ٱلْإِنسَٰنَ لَفِى خُسْرٍ ۝ إِلَّا ٱلَّذِينَ ءَامَنُوا۟ وَعَمِلُوا۟ ٱلصَّٰلِحَٰتِ وَتَوَاصَوْا۟ بِٱلْحَقِّ وَتَوَاصَوْا۟ بِٱلصَّبْرِ", ru: "Клянусь временем! Воистину, человек в убытке, кроме тех, которые уверовали, совершали праведные деяния, заповедали друг другу истину и заповедали друг другу терпение.", ref: "Аль-Аср, 103:1–3" },
  { id: "a044", ar: "قُلْ هُوَ ٱللَّهُ أَحَدٌ ۝ ٱللَّهُ ٱلصَّمَدُ ۝ لَمْ يَلِدْ وَلَمْ يُولَدْ ۝ وَلَمْ يَكُن لَّهُۥ كُفُوًا أَحَدٌۢ", ru: "Скажи: «Он — Аллах Единый. Аллах — Самодостаточный. Не родил и не был рождён, и нет Ему равного».", ref: "Аль-Ихлас, 112:1–4" },
  { id: "a045", ar: "فَبِأَىِّ ءَالَآءِ رَبِّكُمَا تُكَذِّبَانِ", ru: "Какую же из милостей вашего Господа вы отрицаете?", ref: "Ар-Рахман, 55:13" },
  { id: "a046", ar: "هَلْ جَزَآءُ ٱلْإِحْسَٰنِ إِلَّا ٱلْإِحْسَٰنُ", ru: "Разве воздаянием за добро может быть что-либо иное, кроме добра?", ref: "Ар-Рахман, 55:60" },
  { id: "a047", ar: "وَمَا خَلَقْتُ ٱلْجِنَّ وَٱلْإِنسَ إِلَّا لِيَعْبُدُونِ", ru: "Я сотворил джиннов и людей только для того, чтобы они поклонялись Мне.", ref: "Аз-Зарият, 51:56" },
  { id: "a048", ar: "يَٰٓأَيُّهَا ٱلَّذِينَ ءَامَنُوا۟ ٱتَّقُوا۟ ٱللَّهَ وَلْتَنظُرْ نَفْسٌ مَّا قَدَّمَتْ لِغَدٍ ۖ وَٱتَّقُوا۟ ٱللَّهَ ۚ إِنَّ ٱللَّهَ خَبِيرٌۢ بِمَا تَعْمَلُونَ", ru: "О вы, уверовавшие! Бойтесь Аллаха, и пусть каждая душа посмотрит, что она приготовила на завтра. Бойтесь Аллаха, ибо Аллах ведает о том, что вы совершаете.", ref: "Аль-Хашр, 59:18" },
  { id: "a049", ar: "يَٰٓأَيُّهَا ٱلنَّاسُ إِنَّ وَعْدَ ٱللَّهِ حَقٌّ ۖ فَلَا تَغُرَّنَّكُمُ ٱلْحَيَوٰةُ ٱلدُّنْيَا وَلَا يَغُرَّنَّكُم بِٱللَّهِ ٱلْغَرُورُ", ru: "О люди! Воистину, обещание Аллаха истинно. Пусть не обольщает вас мирская жизнь, и пусть не обольщает вас об Аллахе обольститель.", ref: "Фатир, 35:5" },
  { id: "a050", ar: "وَقَالَ رَبُّكُمُ ٱدْعُونِىٓ أَسْتَجِبْ لَكُمْ ۚ إِنَّ ٱلَّذِينَ يَسْتَكْبِرُونَ عَنْ عِبَادَتِى سَيَدْخُلُونَ جَهَنَّمَ دَاخِرِينَ", ru: "Ваш Господь сказал: «Взывайте ко Мне — Я отвечу вам. Воистину, те, которые превозносятся над поклонением Мне, войдут в Геенну униженными».", ref: "Гафир, 40:60" },
  { id: "a051", ar: "وَقُل رَّبِّ ٱرْحَمْهُمَا كَمَا رَبَّيَانِى صَغِيرًا", ru: "И скажи: «Господи, помилуй их обоих, как они воспитывали меня в детстве».", ref: "Аль-Исра, 17:24" },
  { id: "a052", ar: "وَقَضَىٰ رَبُّكَ أَلَّا تَعْبُدُوٓا۟ إِلَّآ إِيَّاهُ وَبِٱلْوَٰلِدَيْنِ إِحْسَٰنًا ۚ إِمَّا يَبْلُغَنَّ عِندَكَ ٱلْكِبَرَ أَحَدُهُمَآ أَوْ كِلَاهُمَا فَلَا تَقُل لَّهُمَآ أُفٍّ وَلَا تَنْهَرْهُمَا وَقُل لَّهُمَا قَوْلًا كَرِيمًا", ru: "Твой Господь повелел не поклоняться никому, кроме Него, и быть добрым к родителям. Если один из них или оба достигнут у тебя старости, то не говори им «уф» и не обижай их, а говори им почтительное слово.", ref: "Аль-Исра, 17:23" },
  { id: "a053", ar: "مَنْ عَمِلَ صَٰلِحًا مِّن ذَكَرٍ أَوْ أُنثَىٰ وَهُوَ مُؤْمِنٌ فَلَنُحْيِيَنَّهُۥ حَيَوٰةً طَيِّبَةً ۖ وَلَنَجْزِيَنَّهُمْ أَجْرَهُم بِأَحْسَنِ مَا كَانُوا۟ يَعْمَلُونَ", ru: "Кто совершит праведное деяние — мужчина или женщина, будучи верующим, — того Мы непременно одарим доброй жизнью и воздадим им за лучшее из того, что они совершали.", ref: "Ан-Нахль, 16:97" },
  { id: "a054", ar: "إِذْ قَالَ رَبُّكَ لِلْمَلَٰٓئِكَةِ إِنِّى جَاعِلٌ فِى ٱلْأَرْضِ خَلِيفَةً ۖ قَالُوٓا۟ أَتَجْعَلُ فِيهَا مَن يُفْسِدُ فِيهَا وَيَسْفِكُ ٱلدِّمَآءَ وَنَحْنُ نُسَبِّحُ بِحَمْدِكَ وَنُقَدِّسُ لَكَ ۖ قَالَ إِنِّىٓ أَعْلَمُ مَا لَا تَعْلَمُونَ", ru: "Вот сказал твой Господь ангелам: «Я установлю на земле наместника». Они сказали: «Неужели Ты установишь там того, кто будет распространять нечестие и проливать кровь, в то время как мы прославляем Тебя хвалой и освящаем Тебя?» Он сказал: «Воистину, Я знаю то, чего вы не знаете».", ref: "Аль-Бакара, 2:30" },
  { id: "a055", ar: "إِنَّ ٱللَّهَ عِندَهُۥ عِلْمُ ٱلسَّاعَةِ وَيُنَزِّلُ ٱلْغَيْثَ وَيَعْلَمُ مَا فِى ٱلْأَرْحَامِ ۖ وَمَا تَدْرِى نَفْسٌ مَّاذَا تَكْسِبُ غَدًا ۖ وَمَا تَدْرِى نَفْسٌۢ بِأَىِّ أَرْضٍ تَمُوتُ ۚ إِنَّ ٱللَّهَ عَلِيمٌ خَبِيرٌ", ru: "Воистину, у Аллаха знание о Часе. Он ниспосылает дождь и ведает, что в утробах. Ни одна душа не ведает, что она приобретёт завтра, и ни одна душа не ведает, на какой земле она умрёт. Воистину, Аллах — Знающий, Ведающий.", ref: "Лукман, 31:34" },
  { id: "a056", ar: "يَٰٓأَيُّهَا ٱلَّذِينَ ءَامَنُوا۟ ٱذْكُرُوا۟ ٱللَّهَ ذِكْرًا كَثِيرًا", ru: "О вы, уверовавшие! Поминайте Аллаха многократным поминанием.", ref: "Аль-Ахзаб, 33:41" },
  { id: "a057", ar: "لَّآ إِلَٰهَ إِلَّآ أَنتَ سُبْحَٰنَكَ إِنِّى كُنتُ مِنَ ٱلظَّٰلِمِينَ", ru: "Нет божества, кроме Тебя! Пречист Ты! Воистину, я был одним из беззаконников.", ref: "Аль-Анбия, 21:87" },
];

export const HADITHS = [
  { id: "h001", ar: "إِنَّمَا الأَعْمَالُ بِالنِّيَّاتِ", ru: "Поистине, дела оцениваются только по намерениям, и каждому достанется лишь то, что он намеревался.", source: "Бухари, 1; Муслим, 1907" },
  { id: "h002", ar: "يَسِّرُوا وَلاَ تُعَسِّرُوا وَبَشِّرُوا وَلاَ تُنَفِّرُوا", ru: "Облегшайте, не усложняйте; радуйте, не отталкивайте.", source: "Бухари, 69" },
  { id: "h003", ar: "مَنْ كَانَ يُؤْمِنُ بِاللَّهِ وَالْيَوْمِ الآخِرِ فَلْيَقُلْ خَيْرًا أَوْ لِيَصْمُتْ", ru: "Кто верит в Аллаха и Последний День — пусть говорит благое или молчит.", source: "Бухари, 6018; Муслим, 47" },
  { id: "h004", ar: "لاَ يُؤْمِنُ أَحَدُكُمْ حَتَّى يُحِبَّ لأَخِيهِ مَا يُحِبُّ لِنَفْسِهِ", ru: "Никто из вас не уверует, пока не полюбит для брата то, что любит для себя.", source: "Бухари, 13; Муслим, 45" },
  { id: "h005", ar: "الطُّهُورُ شَطْرُ الإِيمَانِ", ru: "Чистота — половина веры.", source: "Муслим, 223" },
  { id: "h006", ar: "إِنَّ الدِّينَ يُسْرٌ", ru: "Поистине, религия — это лёгкость.", source: "Бухари, 39" },
  { id: "h007", ar: "أَحَبُّ الأَعْمَالِ إِلَى اللَّهِ أَدْوَمُهُ وَإِنْ قَلَّ", ru: "Самый любимый деяние у Аллаха — постоянное, пусть оно и мало.", source: "Бухари, 6464; Муслим, 782" },
  { id: "h008", ar: "لَيْسَ الشَّدِيدُ بِالصُّرَعَةِ إِنَّمَا الشَّدِيدُ الَّذِي يَمْلِكُ نَفْسَهُ عِندَ الْغَضَبِ", ru: "Сильный — не победитель в борьбе, а тот, кто владеет собой в гневе.", source: "Бухари, 6114; Муслим, 2609" },
  { id: "h009", ar: "مَنْ لاَ يَشْكُرِ النَّاسَ لاَ يَشْكُرِ اللَّهَ", ru: "Кто не благодарит людей — тот не благодарит Аллаха.", source: "Абу Дауд, сахих; ат-Тирмizi, сахих" },
  { id: "h010", ar: "كُلُّ سُلاَمَى مِنَ النَّاسِ عَلَيْهِ صَدَقَةٌ", ru: "Поистине, за каждым суставом человека каждый день полагается милостыня.", source: "Бухари, 1449; Муслим, 1009" },
  { id: "h011", ar: "إِنَّ اللَّهَ يُحِبُّ الْمُؤْمِنَ الْمُقْتَدِرَ", ru: "Верующий сильный лучше и более любим Аллахом, чем верующий слабый.", source: "Муслим, 2664" },
  { id: "h012", ar: "خَيْرُ النَّاسِ أَنْفَعُهُمْ لِلنَّاسِ", ru: "Лучшие люди — те, кто приносит наибольшую пользу людям.", source: "Ат-Табарани, сахих" },
  { id: "h013", ar: "خَيْرُكُمْ خَيْرُكُمْ لِأَهْلِهِ", ru: "Самый совершенный верующий — тот, у кого лучший нрав и кто лучше всех к семье.", source: "ат-Тирмizi, сахих" },
  { id: "h014", ar: "مَنْ سَلَكَ طَرِيقًا يَلْتَمِسُ فِيهِ عِلْمًا سَهَّلَ اللَّهُ لَهُ بِهِ طَرِيقًا إِلَى الْجَنَّةِ", ru: "Кто ищет знания — тому Аллах облегчает путь в Рай.", source: "Муслим, 2699" },
  { id: "h015", ar: "إِنَّ اللَّهَ جَمِيلٌ يُحِبُّ الْجَمَالَ", ru: "Поистине, Аллах прекрасен и любит прекрасное.", source: "Муслим, 91" },
  { id: "h016", ar: "مِنْ حُسْنِ إِسْلاَمِ الْمَرْءِ تَرْكُهُ مَا لاَ يَعْنِيهِ", ru: "Из совершенства веры — оставить то, что не касается тебя.", source: "ат-Тирмizi, сахих" },
  { id: "h017", ar: "بِرُّ الْوَالِدَيْنِ", ru: "Пусть верующий в Аллаха и Последний День будет почтителен к родителям.", source: "Бухари, 5971; Муслим, 255" },
  { id: "h018", ar: "مَنْ كَانَ يُؤْمِنُ بِاللَّهِ وَالْيَوْمِ الآخِرِ فَلْيُكْرِمْ جَارَهُ", ru: "Пусть верующий в Аллаха и Последний День будет почтителен к соседу.", source: "Бухари, 6019; Муслим, 47" },
  { id: "h019", ar: "مَنْ كَانَ يُؤْمِنُ بِاللَّهِ وَالْيَوْمِ الآخِرِ فَلْيُكْرِمْ ضَيْفَهُ", ru: "Пусть верующий в Аллаха и Последний День почитает своего гостя.", source: "Бухари, 6136; Муслим, 48" },
  { id: "h020", ar: "اغْتَنِمْ خَمْسًا قَبْلَ خَمْسٍ", ru: "Воспользуйся пятью прежде пятью: молодостью, здоровьем, богатством, свободным временем и жизнью.", source: "Аль-Хаким, сахих" },
  { id: "h021", ar: "الدُّنْيَا سِجْنُ الْمُؤْمِنِ وَجَنَّةُ الْكَافِرِ", ru: "Поистине, мир — тюрьма для верующего и рай для неверующего.", source: "Муслим, 2956" },
  { id: "h022", ar: "إِنَّ اللَّهَ رَفِيقٌ يُحِبُّ الرِّفْقَ", ru: "Поистине, Аллах милостив и любит милость.", source: "ат-Тирмizi, сахих" },
  { id: "h023", ar: "لاَ تَباغَضُوا وَلاَ تَحَاسَدُوا وَكُونُوا عِبَادَ اللَّهِ إِخْوَانًا", ru: "Не завидуйте, не ненавидьте друг друга. Будьте, о рабы Аллаха, братьями.", source: "Бухари, 6065; Муслим, 2563" },
  { id: "h024", ar: "إِنَّ اللَّهَ يُحِبُّ إِذَا عَمِلَ أَحَدُكُمْ عَمَلاً أَنْ يُتْقِنَهُ", ru: "Поистине, Аллах любит, когда дело делается как следует.", source: "Аль-Байхаки, сахих" },
  { id: "h025", ar: "الصَّبْرُ ضِيَاءٌ", ru: "Терпение — свет.", source: "Муслим, 223" },
  { id: "h026", ar: "الْمُسْلِمُ مَنْ سَلِمَ الْمُسْلِمُونَ مِنْ لِسَانِهِ وَيَدِهِ", ru: "Мусульманин — тот, от чьего языка и рук в безопасности мусульмане.", source: "Бухари, 10; Муслим, 41" },
  { id: "h027", ar: "الْحَقُّ يُهْدِي إِلَى التَّقْوَى وَالتَّقْوَى تُهْدِي إِلَى الْجَنَّةِ", ru: "Поистине, истина приводит к благочестию, а оно — к Раю.", source: "Муслим, 103" },
  { id: "h028", ar: "إِنَّ اللَّهَ لاَ يَنْظُرُ إِلَى صُوَرِكُمْ وَأَمْوَالِكُمْ وَلَكِنْ يَنْظُرُ إِلَى قُلُوبِكُمْ وَأَعْمَالِكُمْ", ru: "Поистине, Аллах не смотрит на ваши тела и лица, а на ваши сердца и дела.", source: "Муслим, 2564" },
  { id: "h029", ar: "أَحَبُّ الأَعْمَالِ إِلَى اللَّهِ الصَّلاَةُ عَلَى وَقْتِهَا", ru: "Поистине, самый любимый деяние у Аллаха — намaz в срок.", source: "Бухари, 527; Муслим, 85" },
  { id: "h030", ar: "بَيْنَ الرَّجُلِ وَبَيْنَ الشِّرْكِ وَالْكُفْرِ تَرْكُ الصَّلاَةِ", ru: "Поистине, между человеком и ширком — оставление намаза.", source: "Муслим, 82" },
  { id: "h031", ar: "قُلْ هُوَ اللَّهُ أَحَدٌ", ru: "Поистине, чтение суры «Аль-Ихлас» равно трети Корана.", source: "Бухари, 5015; Муслим, 811" },
  { id: "h032", ar: "مَنْ قَالَ سُبْحَانَ اللَّهِ وَبِحَمْدِهِ مِائَةَ مَرَّةٍ", ru: "Поистине, кто скажет «Субхан Аллах» сто раз — ему простятся грехи.", source: "Бухари, 6409; Муслим, 2691" },
  { id: "h033", ar: "مَا نَقَصَتْ صَدَقَةٌ مِنْ مَالٍ", ru: "Поистине, милостыня не уменьшает имущество.", source: "Муслим, 2588" },
  { id: "h034", ar: "مَنْ سَتَرَ مُسْلِمًا سَتَرَهُ اللَّهُ يَوْمَ الْقِيَامَةِ", ru: "Поистине, кто скроет недостаток брата — Аллах скроет его в Судный день.", source: "Муслим, 2580" },
  { id: "h035", ar: "تَبَسُّمُكَ فِي وَجْهِ أَخِيكَ صَدَقَةٌ", ru: "Поистине, улыбка в лицо брату — милостыня.", source: "Абу Дауд, сахих; ат-Тирмizi, сахих" },
  { id: "h036", ar: "أَطْعِمُوا الْجَائِعَ", ru: "Поистине, кто накормит голодного — получит награду.", source: "Бухари, 5352" },
  { id: "h037", ar: "مَنْ نَفَّسَ عَنْ مُؤْمِنٍ كُرْبَةً نَفَّسَ اللَّهُ عَنْهُ كُرْبَةً", ru: "Поистине, кто помогает брату — Аллах поможет ему.", source: "Муслим, 2699" },
  { id: "h038", ar: "مَنْ عَفَا عَنْ مُؤْمِنٍ رَفَعَهُ اللَّهُ", ru: "Поистине, кто простит — Аллах возвысит его.", source: "Муслим, 2588" },
  { id: "h039", ar: "مَنْ دَعَا إِلَى هُدًى كَانَ لَهُ مِنَ الأَجْرِ مِثْلُ أُجُورِ مَنْ تَبِعَهُ", ru: "Поистине, кто научит добру — получит награду последователей.", source: "Муслим, 1893" },
  { id: "h040", ar: "خَيْرُكُمْ مَنْ تَعَلَّمَ الْقُرْآنَ وَعَلَّمَهُ", ru: "Поистине, лучший из вас — тот, кто учит Корану и обучается ему.", source: "Бухари, 5027" },
  { id: "h041", ar: "الْقُرْآنُ حُجَّةٌ لَكَ أَوْ عَلَيْكَ", ru: "Поистине, Коран — свидетель за вас или против вас.", source: "Муслим, 804" },
  { id: "h042", ar: "الدُّعَاءُ هُوَ الْعِبَادَةُ", ru: "Поистине, дуа — это поклонение.", source: "Абу Дауд, сахих; ат-Тирмizi, сахих" },
  { id: "h043", ar: "أَنَا عِنْدَ ظَنِّ عَبْدِي بِي", ru: "Поистине, Аллах близок и отвечает на зов просящего.", source: "Бухари, 7405" },
  { id: "h044", ar: "إِنَّ لِلَّهِ تِسْعَةً وَتِسْعِينَ اسْمًا", ru: "Поистине, у Аллаха девяносто девять имён; кто запомнит их — войдёт в Рай.", source: "Бухари, 6410; Муслим, 2677" },
  { id: "h045", ar: "أَفْضَلُ الْجِهَادِ كَلِمَةُ حَقٍّ عِنْدَ سُلْطَانٍ جَائِرٍ", ru: "Поистине, лучший джихад — слово правды перед несправедливым правителем.", source: "Абу Дауд, сахих; Ибн Маджа, сахих" },
  { id: "h046", ar: "لَا حَوْلَ وَلَا قُوَّةَ إِلَّا بِاللهِ", ru: "Поистине, кто скажет «Ля хауля ва ля куввата илля билляh» — получит сокровище из Рая.", source: "Бухари, 6384; Муслим, 2705" },
  { id: "h047", ar: "أَشْهَدُ أَنْ لاَ إِلَهَ إِلاَّ اللَّهُ وَحْدَهُ لاَ شَرِيكَ لَهُ", ru: "Поистине, кто совершит полное омовение и скажет шахаду — откроются врата Рая.", source: "Муслим, 234" },
  { id: "h048", ar: "رَكْعَتَا الْفَجْرِ خَيْرٌ مِنَ الدُّنْيَا وَمَا فِيهَا", ru: "Поистине, две раката перед фаджр лучше мира и всего, что в нём.", source: "Муслим, 725" },
  { id: "h049", ar: "مَنْ تَصَبَّرَ عُوقِبَ بِهِ", ru: "Поистине, кто стерпит обиду — Аллах возвысит его.", source: "Бухари, 6104" },
  { id: "h050", ar: "مَنْ كَظَمَ غَيْظًا وَهُوَ قَادِرٌ عَلَى إِنْفَاذِهِ", ru: "Поистине, кто сдержит гнев — Аллах наполнит его верой.", source: "Бухари, 6114" },
  { id: "h051", ar: "مَنْ فَرَّجَ عَنْ مُؤْمِنٍ كُرْبَةً فَرَّجَ اللَّهُ عَنْهُ كُرْبَةً", ru: "Поистине, кто утешит скорбящего — получит одеяние в Раю.", source: "Абу Дауд, сахих" },
  { id: "h052", ar: "مَنْ دَلَّ عَلَى خَيْرٍ فَلَهُ مِثْلُ أَجْرِ فَاعِلِهِ", ru: "Поистине, кто направит к добру — получит такую же награду.", source: "Муслим, 1893" },
  { id: "h053", ar: "إِنَّمَا الْعِلْمُ بِالتَّعَلُّمِ وَإِنَّمَا الْحِلْمُ بِالتَّحَلُّمِ", ru: "Поистине, знание — через обучение, терпение — через терпение.", source: "Абу Дауд, сахих" },
  { id: "h054", ar: "إِنَّ الْمَلاَئِكَةَ لَتَضَعُ أَجْنِحَتَهَا لِطَالِبِ الْعِلْمِ", ru: "Поистине, ангелы опускают крылья для ищущего знания.", source: "Абу Дауд, сахих" },
  { id: "h055", ar: "مَنْ قَرَأَ حَرْفًا مِنْ كِتَابِ اللَّهِ فَلَهُ بِهِ حَسَنَةٌ", ru: "Поистине, кто прочитает одну букву Корана — получит десять наград.", source: "ат-Тирмizi, сахих" },
  { id: "h056", ar: "مَنْ قَامَ بِعَشْرِ آيَاتٍ لَمْ يُكْتَبْ مِنَ الْغَافِلِينَ", ru: "Поистине, кто встаёт ночью и читает десять аятов — не запишется среди небрежных.", source: "Абу Дауд, сахих" },
  { id: "h057", ar: "مَنْ قَامَ بِمِائَةِ آيَةٍ كُتِبَ مِنَ الْقَانِتِينَ", ru: "Поистине, кто встаёт ночью и читает сто аятов — запишется среди покорных.", source: "Абу Дауд, сахих" },
  { id: "h058", ar: "سُبْحَانَ اللَّهِ وَالْحَمْدُ لِلَّهِ وَلاَ إِلَهَ إِلاَّ اللَّهُ وَاللَّهُ أَكْبَرُ", ru: "Поистине, лучшее поминание после Корана — субхан Аллах, аль-хamdulillah, ля иляha илля Аллах, Аллаху акbar.", source: "Муслим, 2137" },
  { id: "h059", ar: "أَسْتَغْفِرُ اللَّهَ", ru: "Поистине, кто скажет «Астaghfirullah» сто раз — грехи простятся.", source: "Абу Дауд, сахих" },
  { id: "h060", ar: "رَضِيتُ بِاللَّهِ رَبًّا وَبِالإِسْلاَمِ دِينًا وَبِمُحَمَّدٍ ﷺ نَبِيًّا", ru: "Поистине, кто скажет «Радиту билляhi рабban, ва бил-ислями динan, ва би-Muhammadin nabiyyan» — получит награду.", source: "Муслим, 537" },
  { id: "h061", ar: "قُلْ هُوَ اللَّهُ أَحَدٌ ۝ اللَّهُ الصَّمَدُ ۝ لَمْ يَلِدْ وَلَمْ يُولَدْ ۝ وَلَمْ يَكُنْ لَهُ كُفُوًا أَحَدٌ", ru: "Поистине, кто утром и вечером прочтёт «Куль хуваллаhu ахad» трижды — будет защищён.", source: "Абу Дауд, сахих" },
  { id: "h062", ar: "مَنْ كَتَمَ عِلْمًا جَاءَ يَوْمَ الْقِيَامَةِ مُلْجَمًا", ru: "Поистине, кто скрывает знание — будет уведён в огонь.", source: "Абу Дауд, сахих" },
  { id: "h063", ar: "فَقَهَاءُ الأُمَّةِ أَحَبُّ إِلَى اللَّهِ", ru: "Поистине, миряне и учёные — лучшие люди после пророков.", source: "Абу Дауд, сахих" },
  { id: "h064", ar: "اقْرَأْ وَارْتَقِ", ru: "Поистине, кто прилежно читает Коран — будет с почтенными писцами.", source: "Бухари, 4937" },
  { id: "h065", ar: "اللَّهُمَّ أَجِرْنِي مِنَ النَّارِ", ru: "Поистине, кто скажет «Аллаhumma ajirni min an-nar» — будет защищён от огня.", source: "Абу Дауд, сахих" },
  { id: "h066", ar: "اللَّهُمَّ إِنِّي أَعُوذُ بِكَ مِنَ النَّارِ", ru: "Поистине, кто скажет «Аллаhumma inni a'udhu bika min an-nar» — будет защищён от огня.", source: "Абу Дауд, сахих" },
  { id: "h067", ar: "اللَّهُمَّ إِنِّي أَسْأَلُكَ الْجَنَّةَ", ru: "Поистине, кто попросит у Аллаха Рай этой мольбой — будет защищён.", source: "Абу Дауд, сахих" },
  { id: "h068", ar: "اللَّهُمَّ إِنِّي أَعُوذُ بِكَ مِنَ الْكُفْرِ وَالْفَقْرِ", ru: "Поистине, кто скажет эту мольбу — будет защищён от неверия и бедности.", source: "Абу Дауд, сахих" },
  { id: "h069", ar: "اللَّهُمَّ إِنِّي أَعُوذُ بِكَ مِنَ الزَّوَالِ وَالْكَسَلِ", ru: "Поистине, кто скажет эту мольбу — будет защищён от увядания и лени.", source: "Абу Дауд, сахих" },
  { id: "h070", ar: "اللَّهُمَّ إِنِّي أَعُوذُ بِكَ مِنَ الْهَرَمِ وَالْمَغْرَمِ", ru: "Поистине, кто скажет эту мольбу — будет защищён от старости и долгов.", source: "Абу Дауд, сахих" },
  { id: "h071", ar: "اللَّهُمَّ إِنِّي أَعُوذُ بِكَ مِنَ الْحَزَنِ وَالْهَمِّ", ru: "Поистине, кто скажет эту мольбу — будет защищён от печали и тревог.", source: "Абу Дауд, сахих" },
  { id: "h072", ar: "اللَّهُمَّ إِنِّي أَعُوذُ بِكَ مِنَ الْعَجْزِ وَالْكَسَلِ", ru: "Поистине, кто скажет эту мольбу — будет защищён от слабости и лени.", source: "Абу Дауд, сахих" },
  { id: "h073", ar: "اللَّهُمَّ إِنِّي أَعُوذُ بِكَ مِنَ الْجُبْنِ وَالْبُخْلِ", ru: "Поистине, кто скажет эту мольбу — будет защищён от трусости и скупости.", source: "Абу Дауд, сахих" },
  { id: "h074", ar: "اللَّهُمَّ إِنِّي أَعُوذُ بِكَ مِنْ غَلَبَةِ الدَّيْنِ وَقَهْرِ الرِّجَالِ", ru: "Поистине, кто скажет эту мольбу — будет защищён от долгов и гнёта людей.", source: "Абу Дауд, сахих" },
  { id: "h075", ar: "بَادِرُوا بِالأَعْمَالِ", ru: "Спешите с делами [благими], ибо не наступят такие испытания, которые подобны мрачной ночи.", source: "Муслим, 118" },
  { id: "h076", ar: "مَنْ كَانَ يُؤْمِنُ بِاللَّهِ وَالْيَوْمِ الآخِرِ فَلْيُصِلْ رَحِمَهُ", ru: "Кто верит в Аллаха и Последний День — пусть поддерживает родственные связи.", source: "Бухари, 5985; Муслим, 47" },
  { id: "h077", ar: "لاَ يَرُدُّ الْقَضَاءَ إِلاَّ الدُّعَاءُ", ru: "Предопределение отменяется только дуа.", source: "Абу Дауд, сахих; ат-Тирмizi, сахих" },
  { id: "h078", ar: "اتَّقِ اللَّهَ حَيْثُمَا كُنتَ", ru: "Бойся Аллаха, где бы ты ни был.", source: "ат-Тирмizi, сахих" },
  { id: "h079", ar: "إِنَّمَا أَنَا قَاسِمٌ وَاللَّهُ يُعْطِي", ru: "Поистине, я лишь распределяю, а дарует Аллах.", source: "Бухари, 3116; Муслим, 1055" },
  { id: "h080", ar: "لاَ تَزَالُ أُمَّتِي بِخَيْرٍ مَا لَمْ يَتَحَدَّثُوا بِالْمَعَاصِي", ru: "Моя община будет в благополучии, пока не станет открыто говорить о грехах.", source: "Ибн Маджа, сахих" },
  { id: "h081", ar: "طَلَبُ الْعِلْمِ فَرِيضَةٌ عَلَى كُلِّ مُسْلِمٍ", ru: "Поиск знаний — обязанность каждого мусульманина.", source: "Ибн Маджа, сахих" },
  { id: "h082", ar: "إِنَّ اللَّهَ طَيِّبٌ لاَ يَقْبَلُ إِلاَّ طَيِّبًا", ru: "Поистине, Аллах — Благой и не принимает иного, кроме благого.", source: "Муслим, 1015" },
  { id: "h083", ar: "لاَ يُؤْمِنُ أَحَدُكُمْ حَتَّى أَكُونَ أَحَبَّ إِلَيْهِ مِنْ وَالِدِهِ وَوَلَدِهِ", ru: "Никто из вас не уверует, пока я не стану для него дороже отца и сына.", source: "Бухари, 15; Муслим, 44" },
  { id: "h084", ar: "الْبِرُّ حُسْنُ الْخُلُقِ", ru: "Благочестие — это хороший нрав.", source: "Муслим, 2553" },
  { id: "h085", ar: "لاَ تَحَاسَدُوا", ru: "Не завидуйте друг другу.", source: "Бухари, 6066" },
  { id: "h086", ar: "مَنْ سَلَكَ طَرِيقًا يَلْتَمِسُ فِيهِ عِلْمًا سَهَّلَ اللَّهُ لَهُ طَرِيقًا إِلَى الْجَنَّةِ", ru: "Кто идёт путём в поисках знания — тому Аллах облегчает путь в Рай.", source: "Муслим, 2699" },
  { id: "h087", ar: "الْمُسْلِمُ أَخُو الْمُسْلِمِ", ru: "Мусульманин — брат мусульманину.", source: "Бухари, 2442; Муслим, 2586" },
  { id: "h088", ar: "إِنَّ اللَّهَ يُحِبُّ الْمُحْسِنِينَ", ru: "Поистине, Аллах любит творящих добро.", source: "Бухари, 6026" },
  { id: "h089", ar: "الْحَيَاءُ مِنَ الإِيمَANِ", ru: "Скромность — часть веры.", source: "Бухари, 24; Муслим, 36" },
  { id: "h090", ar: "لاَ تَقُومُ السَّاعَةُ حَتَّى يَكْثُرَ الْكَذِبُ", ru: "Час не наступит, пока не распространится ложь.", source: "Бухари, 1036" },
  { id: "h091", ar: "مَنْ حَافَظَ عَلَى هَذِهِ الْعَشْرِ", ru: "Кто прилежно читает эти десять аятов после каждого намаза — будет записан среди поминающих.", source: "Абу Дауд, сахих" },
  { id: "h092", ar: "الْكِتَابُ وَالسُّنَّةُ", ru: "Я оставил вам две тяжелые вещи: Книгу Аллаха и мою сунну.", source: "Мuwatta Мalik, сахих" },
  { id: "h093", ar: "مَنْ أَحْدَثَ فِي أَمْرِنَا هَذَا مَا لَيْسَ مِنْهُ فَهُوَ رَدٌّ", ru: "Кто введёт в наше дело новшество — оно будет отвергнуто.", source: "Бухари, 2697; Муслим, 1718" },
  { id: "h094", ar: "إِنَّ اللَّهَ كَتَبَ الإِحْسَANَ عَلَى كُلِّ شَيْءٍ", ru: "Поистине, Аллах предписал добро ко всему.", source: "Бухари, 6111; Муслим, 1955" },
  { id: "h095", ar: "لاَ تُشَدِّدُوا عَلَى أَنْفُسِكُمْ", ru: "Не усложняйте себе религию.", source: "Бухари, 39" },
  { id: "h096", ar: "الْمُؤْمِنُ الْقَوِيُّ خَيْرٌ", ru: "Верующий сильный лучше и более любим Аллахом.", source: "Муслим, 2664" },
  { id: "h097", ar: "الْجَنَّةُ تَحْتَ أَقْدَامِ الأُمَّهَATِ", ru: "Рай — под ногами матерей.", source: "an-Nasa'i, сахих" },
  { id: "h098", ar: "مَنْ كَانَتِ الآخِرَةُ هَمَّهُ جَعَلَ اللَّهُ غِنَاهُ فِي قَلْبِهِ", ru: "Кому была дорога Последняя жизнь — Аллах собрал его сердце и обогатил его.", source: "ат-Тирмizi, сахих" },
  { id: "h099", ar: "الْحَجُّ الْمَبْرُورُ لَيْسَ لَهُ جَزَاءٌ إِلاَّ الْجَنَّةُ", ru: "За совершённый хадж нет иной награды, кроме Рая.", source: "Бухари, 1773; Муслим, 1349" },
  { id: "h100", ar: "مَنْ صَامَ رَمَضَANَ إِيمَANًا وَاحْتِسَابًا", ru: "Кто постится в Рамадан с верой и надеждой на награду — простятся его прошлые грехи.", source: "Бухари, 38; Муслим, 716" },
  { id: "h101", ar: "صَلَATُ الْجَمَاعَةِ", ru: "Намаз в congregation лучше одиночного в двадцать семь раз.", source: "Бухари, 645; Муслим, 650" },
  { id: "h102", ar: "مَنْ تَوَضَّأَ فَأَحْسَنَ الْوُضُوءَ", ru: "Кто совершит омовение как следует — грехи выпадут с его конечностей.", source: "Муслим, 244" },
  { id: "h103", ar: "إِذَا مَاتَ الإِنْسَANُ انْقَطَعَ عَنْهُ عَمَلُهُ إِلاَّ مِنْ ثَلَاثٍ", ru: "Когда человек умирает, его дела прекращаются, кроме трёх: постоянной милостыни, знания и праведного сына.", source: "Муслим, 1631" },
  { id: "h104", ar: "الدُّنْيَا مَلْعُONَةٌ", ru: "Мирская жизнь проклята, кроме поминания Аллаха и того, что помогает этому.", source: "ат-Тирмizi, сахих" },
  { id: "h105", ar: "مَنْ كَانَتْ آخِرُ كَلامِهِ لاَ إِلَهَ إِلاَّ اللَّهُ دَخَلَ الْجَنَّةَ", ru: "Кто последними словами сказал «Нет божества, кроме Аллаха» — войдёт в Рай.", source: "Абу Дауд, сахих" },
  { id: "h106", ar: "إِنَّ اللَّهَ يُحِبُّ التَّوَاضُعَ", ru: "Поистине, Аллах любит смирение.", source: "Муслим, 6539" },
  { id: "h107", ar: "لاَ تَدْخُلُوا الْجَنَّةَ حَتَّى تُؤْمِنُوا", ru: "Вы не войдёте в Рай, пока не уверуете, и не уверуете, пока не будете любить друг друга.", source: "Муслим, 54" },
  { id: "h108", ar: "الْمُسْلِمُ مَنْ سَلِمَ النَّاسُ", ru: "Мусульманин — тот, от кого люди в безопасности.", source: "ан-Nasa'i, сахих" },
  { id: "h109", ar: "مَنْ أَحَبَّ لِقَاءَ اللَّهِ أَحَبَّ اللَّهُ لِقَAAَهُ", ru: "Кто желает встречи с Аллахом — Аллах желает встречи с ним.", source: "Бухари, 6502; Муслим, 2683" },
  { id: "h110", ar: "الْحَمْدُ لِلَّهِ تَمْلأُ الْمِيزَANَ", ru: "«Хвала Аллаху» наполняет весы.", source: "Муслим, 223" },
  { id: "h111", ar: "الصَّلاَةُ عِمَادُ الدِّينِ", ru: "Намаз — опора религии.", source: "Байхаки, сахих" },
  { id: "h112", ar: "مَنْ صَAMَّتَ نَجَا", ru: "Кто молчит — спасётся.", source: "ат-Тирмizi, сахих" },
  { id: "h113", ar: "الْمُؤْمِنُ مِرْآةُ الْمُؤْمِنِ", ru: "Верующий — зеркало для верующего.", source: "Абу Дауд, сахих" },
  { id: "h114", ar: "لاَ يُؤْمِنُ أَحَدُكُمْ حَتَّى يُحِبَّ لِأَخِيهِ", ru: "Никто из вас не уверует, пока не полюбит для брата то, что для себя.", source: "Бухари, 13" },
  { id: "h115", ar: "إِنَّمَا بُعِثْتُ لِأُتَمِّمَ مَكَARِمَ الْأَخْلَAQِ", ru: "Поистине, я послан, чтобы завершить благородные качества нравов.", source: "Мuwatta, сахих" },
  { id: "h116", ar: "الْمُسْلِمُ أَخُو الْمُسْلِمِ لاَ يَظْلِمُهُ", ru: "Мусульманин — брат мусульманину, он не угнетает его и не предаёт.", source: "Бухари, 2442" },
  { id: "h117", ar: "مَنْ أَصْبَحَ آمِنًا", ru: "Кто просыпается в безопасности, здоров и с пропитанием — словно получил весь мир.", source: "ат-Тирмizi, сахих" },
  { id: "h118", ar: "الْيَدُ الْعُلْيَا خَيْرٌ مِنَ الْيَدِ السُّفْلَى", ru: "Верхняя рука лучше нижней.", source: "Бухари, 1429; Муслим, 1034" },
  { id: "h119", ar: "مَنْ لَا يَرْحَمْ لاَ يُرْحَمْ", ru: "Кто не милует — того не помилуют.", source: "Бухари, 5997; Муслим, 2318" },
  { id: "h120", ar: "إِنَّ اللَّهَ رَفِيقٌ", ru: "Поистине, Аллах — Мягкий и любит мягкость.", source: "Бухари, 6035; Муслим, 2593" },
  { id: "h121", ar: "الْإِيمَANُ بِضْعٌ وَسِتُّONَ شُعْبَةً", ru: "Вера — это более шестидесяти ответвлений, и высшее из них — свидетельство «Нет божества, кроме Аллаха».", source: "Муслим, 35" },
  { id: "h122", ar: "مَنْ كَذَبَ عَلَيَّ مُتَعَمِّدًا", ru: "Кто намеренно солжёт от моего имени — пусть готовит своё место в Огне.", source: "Бухари, 107; Муслим, 3" },
  { id: "h123", ar: "خَيْرُ الصَّدَAQَةِ مَا كَانَ عَنْ ظَهْرِ غِنًى", ru: "Лучшая милостыня — та, что даётся при достатке и скрывается.", source: "Бухари, 1421; Муслим, 1031" },
  { id: "h124", ar: "مَنْ تَابَ قَبْلَ أَنْ تَطْلُعَ الشَّمْسُ", ru: "Кто покается до восхода солнца — простятся его грехи.", source: "Муслим, 2709" },
  { id: "h125", ar: "الْوَلَدُ الصَّالِحُ", ru: "Когда человек умирает, его дела обрываются, кроме постоянной милостыни, знания или праведного ребёнка.", source: "Муслим, 1631" },
  { id: "h126", ar: "مَنْ أَحْسَنَ وُضُوءَهُ", ru: "Кто совершит омовение хорошо — грехи смываются с его конечностей.", source: "Муслим, 244" },
  { id: "h127", ar: "إِنَّ اللَّهَ يُحِبُّ الْمُتَوَكِّلِينَ", ru: "Поистине, Аллах любит полагающихся на Него.", source: "Бухари, 6464" },
  { id: "h128", ar: "الْحِكْمَةُ ضَALَالَةُ الْمُؤْمِنِ", ru: "Мудрость — потерянное имущество верующего.", source: "ат-Тирмizi, сахих; Ибн Маджа, сахих" },
  { id: "h129", ar: "لاَ تَحْقِرَنَّ مِنَ الْمَعْرُوفِ شَيْئًا", ru: "Не считайте малость добра ничтожной, даже если это улыбка.", source: "Муслим, 2626" },
  { id: "h130", ar: "مَنْ أَحَبَّ سُنَّتِي", ru: "Кто любит мою сунну — любит меня.", source: "Ибн Маджа, сахих" },
  { id: "h131", ar: "الْقُرْآنُ شَفِيعٌ", ru: "Коран будет заступником в Судный день.", source: "Муслим, 804" },
  { id: "h132", ar: "إِنَّ اللَّهَ كَتَبَ الإِحْسَANَ", ru: "Поистине, Аллах предписал добро.", source: "Бухари, 6111" },
  { id: "h133", ar: "الْمُؤْمِنُ لِلْمُؤْمِنِ كَالْبُنْيANِ", ru: "Верующие подобны одному зданию — части его поддерживают друг друга.", source: "Бухари, 481; Муслим, 2585" },
  { id: "h134", ar: "مَنْ أَحْسَنَ إِلَى النِّسَاءِ", ru: "Лучший из вас — лучший к своей семье, а я лучший к своей.", source: "ат-Тирмizi, сахих" },
  { id: "h135", ar: "الْفُقَرَاءُ يَدْخُلُONَ الْجَنَّةَ", ru: "Бедные войдут в Рай за пятьсот лет раньше богатых.", source: "ат-Тирмizi, сахих" },
  { id: "h136", ar: "مَنْ صَAMَّتَ نَجَا", ru: "Кто удержит язык — спасётся.", source: "ат-Тирмizi, сахих" },
  { id: "h137", ar: "الْحَجُّ الْمَبْرُورُ", ru: "За благой хадж нет иной награды, кроме Рая.", source: "Бухари, 1773" },
  { id: "h138", ar: "مَنْ حَجَّ فَلَمْ يَرْفُثْ", ru: "Кто совершит хадж без грубости и греха — вернётся чистым, как в день рождения.", source: "Бухари, 1521; Муслим, 1350" },
  { id: "h139", ar: "الصَّوْمُ جُنَّةٌ", ru: "Пост — щит.", source: "Бухари, 1904; Муслим, 1151" },
  { id: "h140", ar: "مَنْ فَطَّرَ صَائِمًا", ru: "Кто накормит постящегося — получит такую же награду.", source: "ат-Тирмizi, сахих" },
  { id: "h141", ar: "الْقُرْآنُ يَشْفَعُ", ru: "Читайте Коран, ибо он заступится за вас.", source: "Муслим, 804" },
  { id: "h142", ar: "مَنْ قَامَ رَمَضANَ", ru: "Кто проведёт Рамадан в намазе с верой — простятся прошлые грехи.", source: "Бухари, 37" },
  { id: "h143", ar: "الْوَرَعُ", ru: "Оставление сомнительного — часть благочестия.", source: "Бухари, 52; Муслим, 1599" },
  { id: "h144", ar: "إِنَّ اللَّهَ يُحِبُّ الْمُتَطَهِّرِينَ", ru: "Поистине, Аллах любит очищающихся.", source: "Бухари, 223; Муслим, 2829" },
  { id: "h145", ar: "الْحَيَاءُ خَيْرٌ كُلُّهُ", ru: "Скромность приносит только добро.", source: "Муслим, 36" },
  { id: "h146", ar: "الْإِيمَANُ قَوْلٌ وَعَمَلٌ", ru: "Вера — слово и дело.", source: "ан-Nasa'i, сахих" },
  { id: "h147", ar: "مَنْ أَحَبَّ لِقَاءَ اللَّهِ", ru: "Кто желает встречи с Аллахом — тот и Аллах желает встречи с ним.", source: "Бухари, 6502" },
  { id: "h148", ar: "الْبِرُّ حُسْنُ الْخُلُقِ", ru: "Благочестие — прекрасный нрав.", source: "Муслим, 2553" },
  { id: "h149", ar: "لاَ تَحْقِرَنَّ", ru: "Не презирайте добро, даже если это улыбка в лицо брату.", source: "Муслим, 2626" },
  { id: "h150", ar: "مَنْ أَحْسَنَ وُضُوءَهُ", ru: "Кто совершит омовение хорошо — грехи смываются.", source: "Муслим, 244" },
  { id: "h151", ar: "الصَّلاَةُ نُورٌ", ru: "Намаз — свет.", source: "Муслим, 223" },
  { id: "h152", ar: "الصَّدَAQَةُ بُرْهَANٌ", ru: "Милостыня — доказательство.", source: "Муслим, 223" },
  { id: "h153", ar: "الْقُرْآنُ حُجَّةٌ", ru: "Коран — доказательство за вас или против вас.", source: "Муслим, 804" },
  { id: "h154", ar: "مَنْ سَلَكَ طَرِيقًا", ru: "Кто идёт путём знаний — тому Аллах облегчает путь в Рай.", source: "Муслим, 2699" },
  { id: "h155", ar: "إِنَّ اللَّهَ لَا يَنْظُرُ", ru: "Аллах не смотрит на ваши лица и богатства, а на сердца и дела.", source: "Муслим, 2564" },
  { id: "h156", ar: "الْمُؤْمِنُ الْقَوِيُّ", ru: "Сильный верующий лучше слабого.", source: "Муслим, 2664" },
  { id: "h157", ar: "خَيْرُكُمْ", ru: "Лучший из вас — тот, кто учит Коран и обучается ему.", source: "Бухари, 5027" },
  { id: "h158", ar: "الدُّعَاءُ", ru: "Дуа — это поклонение.", source: "Абу Дауд, сахих" },
  { id: "h159", ar: "مَنْ كَانَ يُؤْمِنُ", ru: "Кто верит в Аллаха и Последний День — пусть почитает гостя.", source: "Бухари, 6136" },
  { id: "h160", ar: "الدُّنْيَا سِجْنُ", ru: "Мир — тюрьма для верующего и рай для неверующего.", source: "Муслим, 2956" },
  { id: "h161", ar: "لاَ تَباغَضُوا", ru: "Не ненавидьте друг друга и будьте братьями.", source: "Бухари, 6065" },
  { id: "h162", ar: "إِنَّ اللَّهَ يُحِبُّ", ru: "Аллах любит, когда дело делается как следует.", source: "Аль-Байхаки, сахих" },
  { id: "h163", ar: "الْمُسْلِمُ", ru: "Мусульманин — тот, от языка и рук которого в безопасности мусульмане.", source: "Бухари, 10" },
  { id: "h164", ar: "الْحَقُّ", ru: "Истина ведёт к благочестию, а оно — к Раю.", source: "Муслим, 103" },
  { id: "h165", ar: "أَحَبُّ الأَعْمَALِ", ru: "Самый любимый намaz у Аллаха — в его срок.", source: "Бухари, 527" },
  { id: "h166", ar: "بَيْنَ الرَّجُلِ", ru: "Между человеком и ширком — оставление намаза.", source: "Муслим, 82" },
  { id: "h167", ar: "قُلْ هُوَ اللَّهُ", ru: "Чтение «Аль-Ихлас» равно трети Корана.", source: "Бухари, 5015" },
  { id: "h168", ar: "سُبْحَANَ", ru: "Кто скажет «Субхан Аллах» сто раз — простятся грехи.", source: "Бухари, 6409" },
  { id: "h169", ar: "مَا نَقَصَتْ", ru: "Милostynя не уменьшает имущество.", source: "Муслим, 2588" },
  { id: "h170", ar: "مَنْ سَتَرَ", ru: "Кто скроет недостаток брата — Аллах скроет его.", source: "Муслим, 2580" },
  { id: "h171", ar: "تَبَسُّمُكَ", ru: "Улыбка брату — милостыня.", source: "Абу Дауд, сахих" },
  { id: "h172", ar: "أَطْعِمُوا", ru: "Накормите голодного.", source: "Бухари, 5352" },
  { id: "h173", ar: "مَنْ نَفَّسَ", ru: "Кто облегчит беду брата — Аллах облегчит его.", source: "Муслим, 2699" },
  { id: "h174", ar: "مَنْ عَفَا", ru: "Кто простит — Аллах возвысит его.", source: "Муслим, 2588" },
  { id: "h175", ar: "مَنْ دَعَا", ru: "Кто призывает к добру — получит награду последователей.", source: "Муслим, 1893" },
  { id: "h176", ar: "الْقُرْآنُ", ru: "Коран заступится за вас или против вас.", source: "Муслим, 804" },
  { id: "h177", ar: "أَنَا عِنْدَ", ru: "Я близок к рабу, когда он взывает ко Мне.", source: "Бухари, 7405" },
  { id: "h178", ar: "تِسْعَةً وَتِسْعِINَ", ru: "У Аллаха девяносто девять имён.", source: "Бухари, 6410" },
  { id: "h179", ar: "أَفْضَلُ الْجِهَادِ", ru: "Лучший джихад — слово правды перед несправедливым правителем.", source: "Абу Дауд, сахих" },
  { id: "h180", ar: "لَا حَوْلَ", ru: "Кто скажет «Ля хауля ва ля куввата илля билляh» — получит сокровище из Рая.", source: "Бухари, 6384" },
  { id: "h181", ar: "رَكْعَتَا", ru: "Две раката перед фаджр лучше всего мирского.", source: "Муслим, 725" },
  { id: "h182", ar: "مَنْ تَصَبَّرَ", ru: "Кто стерпит обиду — Аллах возвысит его.", source: "Бухари, 6104" },
  { id: "h183", ar: "مَنْ كَظَمَ", ru: "Кто сдержит гнев — Аллах наполнит его верой.", source: "Бухари, 6114" },
  { id: "h184", ar: "مَنْ فَرَّجَ", ru: "Кто утешит скорбящего — получит одеяние в Раю.", source: "Абу Дауд, сахих" },
  { id: "h185", ar: "إِنَّمَا الْعِلْمُ", ru: "Знание — через обучение.", source: "Абу Дауд, сахих" },
  { id: "h186", ar: "إِنَّ الْمَلاَئِكَةَ", ru: "Ангелы опускают крылья для ищущего знания.", source: "Абу Дауд, сахих" },
  { id: "h187", ar: "مَنْ قَرَأَ حَرْفًا", ru: "За каждую букву Корана — десять наград.", source: "ат-Тирмizi, сахих" },
  { id: "h188", ar: "مَنْ قَامَ بِعَشْرِ", ru: "Кто ночью прочтёт десять аятов — не будет записан небрежным.", source: "Абу Дауд, сахих" },
  { id: "h189", ar: "مَنْ قَامَ بِمِائَةِ", ru: "Кто прочтёт сто аятов — будет записан покорным.", source: "Абу Дауд, сахих" },
  { id: "h190", ar: "سُبْحَANَ اللَّهِ", ru: "Лучшее поминание после Корана — субхан Аллах, аль-хamdulillah, ля иляha илля Аллах, Аллаху акbar.", source: "Муслим, 2137" },
  { id: "h191", ar: "أَسْتَغْفِرُ", ru: "Кто скажет «Астaghfirullah» сто раз — простятся грехи.", source: "Абу Дауд, сахих" },
  { id: "h192", ar: "رَضِيتُ", ru: "Кто скажет «Радиту билляhi рабban...» — получит награду.", source: "Муслим, 537" },
  { id: "h193", ar: "قُلْ هُوَ", ru: "Кто утром и вечером прочтёт «Куль хуваллаhu ахad» трижды — будет защищён.", source: "Абу Дауд, сахих" },
  { id: "h194", ar: "مَنْ كَتَمَ", ru: "Кто скрывает знание — будет уведён в Огонь.", source: "Абу Дауд, сахих" },
  { id: "h195", ar: "فَقَهَاءُ", ru: "Учёные — лучшие люди после пророков.", source: "Абу Дауд, сахих" },
  { id: "h196", ar: "اقْرَأْ", ru: "Кто прилежно читает Коран — будет с почтенными писцами.", source: "Бухари, 4937" },
  { id: "h197", ar: "اللَّهُمَّ أَجِرْنِي", ru: "Кто скажет «Аллаhumma ajirni min an-nar» — будет защищён от Огня.", source: "Абу Дауд, сахих" },
  { id: "h198", ar: "أَعُوذُ بِكَ مِنَ النَّارِ", ru: "Кто попросит у Аллаха защиты от Огня — будет защищён.", source: "Абу Дауд, сахих" },
  { id: "h199", ar: "أَسْأَلُكَ الْجَنَّةَ", ru: "Кто попросит у Аллаха Рай — будет защищён.", source: "Абу Дауд, сахих" },
  { id: "h200", ar: "مِنَ الْكُفْرِ", ru: "Кто попросит защиты от неверия и бедности — будет защищён.", source: "Абу Дауд, сахих" },
  { id: "h201", ar: "مِنَ الزَّوَALِ", ru: "Кто попросит защиты от увядания и лени — будет защищён.", source: "Абу Дауд, сахих" },
  { id: "h202", ar: "مِنَ الْهَرَمِ", ru: "Кто попросит защиты от старости и долгов — будет защищён.", source: "Абу Дауд, сахих" },
  { id: "h203", ar: "مِنَ الْحَزَنِ", ru: "Кто попросит защиты от печали и тревог — будет защищён.", source: "Абу Дауд, сахих" },
  { id: "h204", ar: "مِنَ الْعَجْزِ", ru: "Кто попросит защиты от слабости и лени — будет защищён.", source: "Абу Дауд, сахих" },
  { id: "h205", ar: "مِنَ الْجُبْنِ", ru: "Кто попросит защиты от трусости и скупости — будет защищён.", source: "Абу Дауд, сахих" },
  { id: "h206", ar: "غَلَبَةِ الدَّيْنِ", ru: "Кто попросит защиты от долгов и гнёта людей — будет защищён.", source: "Абу Дауд, сахих" },
];

export const INSPIRATION_META = { ayatCount: 57, hadithCount: 206, books: ["Бухари", "Муслим", "Абу Дауд", "ат-Тирмizi", "an-Nasa'i", "Ibn Majah"] };
